backgroundColor:
{{
(() => {
  const status = snowplow_jobsDetails.data?.[0]?.status ?? "";
  const s = status.toLowerCase();

  // Farbpalette (hell + dezent)
  const colors = {
    green:  "#22c55e",   // published
    yellow: "#fff",   // scheduled/submitted
    blue:   "#fff",   // draft
    gray:   "#fff",   // unpublished*
    red:    "#f03c3c",   // fallback optional
  };

  if (["unpublished_by_admin", "unpublished_by_expiration", "unpublished_by_feed", "unpublished_by_recruiter"].includes(s)) {
    return colors.red;
  }
  if (["scheduled_for_publishing", "submitted_for_publishing"].includes(s)) {
    return colors.yellow;
  }
  if (s === "published") {
    return colors.green;
  }
  if (s === "draft") {
    return colors.blue;
  }
  // Default-Farbe
  return "#FFFFFF";
})()
}}

